  1	import React from 'react';
  2	import { Trans } from 'react-i18next';
  3	
  4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  5	import { Button, ExpandableSection } from '@patternfly/react-core';
  6	
  7	import { RDP_CONSOLE_TYPE, SPICE_CONSOLE_TYPE, VNC_CONSOLE_TYPE } from '../../utils/ConsoleConsts';
  8	import {
  9	  DEFAULT_RDP_FILENAME,
 10	  DEFAULT_RDP_MIMETYPE,
 11	  DEFAULT_VV_FILENAME,
 12	  DEFAULT_VV_MIMETYPE,
 13	} from '../utils/constants';
 14	import { RemoteViewerProps } from '../utils/types';
 15	import { downloadFile, generateDescriptorFile } from '../utils/utils';
 16	
 17	import MoreInformationDefault from './MoreInformationDefault';
 18	
 19	const RemoteViewer: React.FC<RemoteViewerProps> = ({
 20	  onDownload = downloadFile,
 21	  onGenerate = generateDescriptorFile,
 22	  rdp = null,
 23	  spice = null,
 24	  textConnectWithRDP,
 25	  textConnectWithRemoteViewer,
 26	  textMoreInfo,
 27	  textMoreInfoContent,
 28	  textMoreRDPInfo,
 29	  textMoreRDPInfoContent,
 30	  vnc = null,
 31	}) => {
 32	  const { t } = useKubevirtTranslation();
 33	  const [isExpandedDefault, setIsExpandedDefault] = React.useState<boolean>(false);
 34	  const [isExpandedRDP, setIsExpandedRDP] = React.useState<boolean>(false);
 35	
 36	  const console = spice || vnc;
 37	
 38	  const onClickVV = () => {
 39	    const type = spice ? SPICE_CONSOLE_TYPE : VNC_CONSOLE_TYPE;
 40	    if (console) {
 41	      const vv = onGenerate(console, type);
 42	      return onDownload(DEFAULT_VV_FILENAME, vv?.content, vv?.mimeType || DEFAULT_VV_MIMETYPE);
 43	    }
 44	  };
 45	
 46	  const onClickRDP = () => {
 47	    const rdpFile = onGenerate(rdp, RDP_CONSOLE_TYPE);
 48	    return onDownload(
 49	      DEFAULT_RDP_FILENAME,
 50	      rdpFile?.content,
 51	      rdpFile?.mimeType || DEFAULT_RDP_MIMETYPE,
 52	    );
 53	  };
 54	
 55	  return (
 56	    <div className="pf-v5-c-console__remote-viewer">
 57	      <div className="pf-v5-c-console__remote-viewer-launch">
 58	        <Button
 59	          className="pf-v5-c-console__remote-viewer-launch-vv"
 60	          isDisabled={!console}
 61	          onClick={onClickVV}
 62	        >
 63	          {textConnectWithRemoteViewer || t('Launch Remote Viewer')}
 64	        </Button>
 65	        {!!rdp && (
 66	          <Button className="pf-v5-c-console__remote-viewer-launch-rdp" onClick={onClickRDP}>
 67	            {textConnectWithRDP || t('Launch Remote Desktop')}
 68	          </Button>
 69	        )}
 70	      </div>
 71	      {!!console && (
 72	        <ExpandableSection
 73	          isExpanded={isExpandedDefault}
 74	          onToggle={(_event, isExpanded) => setIsExpandedDefault(isExpanded)}
 75	          toggleText={textMoreInfo || t('Remote Viewer Details')}
 76	        >
 77	          <MoreInformationDefault textMoreInfoContent={textMoreInfoContent} />
 78	        </ExpandableSection>
 79	      )}
 80	      {!!rdp && (
 81	        <ExpandableSection
 82	          isExpanded={isExpandedRDP}
 83	          onToggle={(_event, isExpanded) => setIsExpandedRDP(isExpanded)}
 84	          toggleText={textMoreRDPInfo || t('Remote Desktop Details')}
 85	        >
 86	          {textMoreRDPInfoContent ?? (
 87	            <Trans ns="plugin__kubevirt-plugin" t={t}>
 88	              <p>
 89	                Clicking &quot;Launch Remote Desktop&quot; will download an .rdp file and launch{' '}
 90	                <i>Remote Desktop Viewer</i>.
 91	              </p>
 92	              <p>
 93	                Since the RDP is native Windows protocol, the best experience is achieved when used
 94	                on Windows-based desktop.
 95	              </p>
 96	              <p>
 97	                For other operating systems, the <i>Remote Viewer</i> is recommended. If RDP needs
 98	                to be accessed anyway, the <a href="https://www.remmina.org/wp/">Remmina</a> client
 99	                is available.
100	              </p>
101	            </Trans>
102	          )}
103	        </ExpandableSection>
104	      )}
105	    </div>
106	  );
107	};
108	
109	export default RemoteViewer;

